import type { EventCallback, EventPayload } from '../types';

interface Listener {
    id: number;
    callback: EventCallback;
    priority: number;
    active: boolean;
}

export class EventSystem {
    private engine: unknown;
    private listeners: Map<string, Listener[]> = new Map();
    private onceListeners: Map<string, Listener[]> = new Map();
    private history: EventPayload[] = [];
    private maxHistorySize: number = 1000;
    private enabled: boolean = true;
    private eventCounter: number = 0;

    constructor(engine: unknown) {
        this.engine = engine;
    }

    on(event: string, callback: EventCallback, priority: number = 0): () => void {
        if (typeof callback !== 'function') {
            throw new Error('回调必须是函数');
        }

        if (!this.listeners.has(event)) {
            this.listeners.set(event, []);
        }

        const listener: Listener = {
            id: ++this.eventCounter,
            callback,
            priority,
            active: true
        };

        this.listeners.get(event)!.push(listener);
        this.listeners.get(event)!.sort((a, b) => b.priority - a.priority);

        return () => this.off(event, listener.id);
    }

    once(event: string, callback: EventCallback, priority: number = 0): () => void {
        if (typeof callback !== 'function') {
            throw new Error('回调必须是函数');
        }

        if (!this.onceListeners.has(event)) {
            this.onceListeners.set(event, []);
        }

        const listener: Listener = {
            id: ++this.eventCounter,
            callback,
            priority,
            active: true
        };

        this.onceListeners.get(event)!.push(listener);
        this.onceListeners.get(event)!.sort((a, b) => b.priority - a.priority);

        return () => this.offOnce(event, listener.id);
    }

    off(event: string, listenerId: number): void {
        const listeners = this.listeners.get(event);
        if (listeners) {
            const index = listeners.findIndex(l => l.id === listenerId);
            if (index !== -1) {
                listeners.splice(index, 1);
            }
        }
    }

    private offOnce(event: string, listenerId: number): void {
        const listeners = this.onceListeners.get(event);
        if (listeners) {
            const index = listeners.findIndex(l => l.id === listenerId);
            if (index !== -1) {
                listeners.splice(index, 1);
            }
        }
    }

    emit(event: string, data?: unknown): void {
        if (!this.enabled) return;

        const payload: EventPayload = {
            type: event,
            data,
            timestamp: Date.now()
        };

        this.addToHistory(payload);

        const listeners = this.listeners.get(event);
        if (listeners) {
            for (const listener of listeners) {
                if (listener.active) {
                    try {
                        listener.callback(payload);
                    } catch (e) {
                        console.error(`事件处理器错误 [${event}]:`, e);
                    }
                }
            }
        }

        const onceListeners = this.onceListeners.get(event);
        if (onceListeners && onceListeners.length > 0) {
            const toCall = [...onceListeners];
            this.onceListeners.set(event, []);
            
            for (const listener of toCall) {
                if (listener.active) {
                    try {
                        listener.callback(payload);
                    } catch (e) {
                        console.error(`一次性事件处理器错误 [${event}]:`, e);
                    }
                }
            }
        }
    }

    private addToHistory(payload: EventPayload): void {
        this.history.push(payload);
        if (this.history.length > this.maxHistorySize) {
            this.history.shift();
        }
    }

    getHistory(event?: string): EventPayload[] {
        if (event) {
            return this.history.filter(p => p.type === event);
        }
        return [...this.history];
    }

    clearHistory(): void {
        this.history = [];
    }

    enable(): void {
        this.enabled = true;
    }

    disable(): void {
        this.enabled = false;
    }

    isEnabled(): boolean {
        return this.enabled;
    }

    removeAllListeners(event?: string): void {
        if (event) {
            this.listeners.delete(event);
            this.onceListeners.delete(event);
        } else {
            this.listeners.clear();
            this.onceListeners.clear();
        }
    }

    getListenerCount(event?: string): number {
        if (event) {
            const regular = this.listeners.get(event)?.length || 0;
            const once = this.onceListeners.get(event)?.length || 0;
            return regular + once;
        }

        let total = 0;
        this.listeners.forEach(list => total += list.length);
        this.onceListeners.forEach(list => total += list.length);
        return total;
    }
}

export default EventSystem;
